SELECT project_id, data_id, shared_at
FROM data_shares
WHERE shared_with = 0;

SELECT share_id, MAX(shared_at) AS last_shared_at
FROM data_shares
GROUP BY share_id;

SELECT project_name, updated_at
FROM research_projects
ORDER BY updated_at DESC;

SELECT level, ABS(value) as absolute_value
FROM agricultural_data
WHERE factor_id IN (SELECT factor_id FROM factors WHERE factor_type = 'F_LU');

SELECT land_use_type, description
FROM land_use_types
ORDER BY land_use_type ASC;

SELECT COUNT(*) AS total_perennial_land_uses
FROM land_use_types
WHERE classification = 'perennial';
